import { readFileSync, writeFileSync } from 'fs';
import { execSync } from 'child_process';

// Find all sub-control files in the remaining 19 service dirs
const dirs = ['ecs','ec2','elasticache','elasticbeanstalk','elb','emr','eventbridge','glue',
  'inspector','macie','mq','msk','pca','rds','redshift-serverless','sagemaker','route53'];
const base = 'src/shared/services/analyser/controls';

const files = execSync(
  `find ${dirs.map(d => `${base}/${d}`).join(' ')} -name "*.mjs" ! -name "index*" ! -name "base-control*"`,
  { encoding: 'utf8' }
).trim().split('\n').filter(Boolean);

let modified = 0, skipped = 0;

for (const file of files) {
  let code = readFileSync(file, 'utf8');

  // Skip if already migrated
  if (code.includes('persistResourceFinding')) { skipped++; continue; }

  // 1. Add persistResourceFinding to import
  if (code.includes('import { getValue, saveResult }')) {
    code = code.replace(
      'import { getValue, saveResult }',
      'import { getValue, saveResult, persistResourceFinding }'
    );
  } else if (code.includes('import { saveResult, getValue }')) {
    code = code.replace(
      'import { saveResult, getValue }',
      'import { saveResult, getValue, persistResourceFinding }'
    );
  } else if (code.includes('import { saveResult }')) {
    code = code.replace(
      'import { saveResult }',
      'import { saveResult, persistResourceFinding }'
    );
  } else {
    // Need to add import — find the first import line
    const firstImport = code.match(/^import .+ from .+$/m);
    if (firstImport) {
      // Figure out the relative path to analyser/index
      const depth = file.split('/').length - base.split('/').length - 1; // sub-dir depth
      const rel = depth === 1 ? '../../index.js' : '../../../analyser/index.js';
      code = `import { persistResourceFinding } from "${rel}";\n` + code;
    }
  }

  // 2. Find controlId from saveResult call
  const controlIdMatch = code.match(/saveResult\(.+?,\s*['"]([^'"]+)['"]/);
  // Also try this.controlId pattern
  const thisControlId = code.match(/this\.controlId/);

  // 3. Find entity type
  const entityMatch = code.match(/EntityType\.(\w+)/) || code.match(/entityType:\s*(\d+)/);
  const entityType = entityMatch ? `EntityType.${entityMatch[1]}` : "'unknown'";

  // Pattern A: ternary  result.status === 'PASS' ? passing++ : failing++;
  if (code.includes("result.status === 'PASS' ? passing++ : failing++")) {
    // Find the resource variable name from the for-of loop before this line
    const forOfMatch = code.match(/for \(const (\w+) of \w+\)\s*\{[\s\S]*?result\.status === 'PASS' \? passing\+\+ : failing\+\+/);
    const resourceVar = forOfMatch ? forOfMatch[1] : 'resource';
    const controlId = controlIdMatch ? `'${controlIdMatch[1]}'` : (thisControlId ? 'this.controlId' : "'unknown'");

    code = code.replace(
      "result.status === 'PASS' ? passing++ : failing++;",
      `result.status === 'PASS' ? passing++ : failing++;\n      await persistResourceFinding({ company, accountID, entityType: ${entityType}, vertex: ${resourceVar}, controlId: ${controlId}, status: result.status === 'PASS' ? 'PASS' : 'FAIL', resourceId: getValue(${resourceVar}, 'name') });`
    );
    writeFileSync(file, code);
    modified++;
    continue;
  }

  // Pattern B: passingCount++/failingCount++ in class evaluate() — these call saveResult per resource
  // Insert persistResourceFinding after each passingCount++ or failingCount++ block
  if (code.includes('passingCount++') || code.includes('failingCount++')) {
    // Find all for-of loops with resource variables
    const forOfMatches = [...code.matchAll(/for \(const (\w+) of (\w+)\)/g)];
    const resourceVar = forOfMatches.length > 0 ? forOfMatches[forOfMatches.length - 1][1] : 'resource';
    const controlId = thisControlId ? 'this.controlId' : (controlIdMatch ? `'${controlIdMatch[1]}'` : "'unknown'");

    // Find the last saveResult in the file and insert persist before it
    // Actually, insert after each pass/fail decision
    // Pattern: passingCount++; followed by saveResult on next lines
    // Or: failingCount++; followed by saveResult
    // Safest: add after the innermost for-loop's pass/fail, before saveResult

    // Replace the pattern where we see the resource loop's pass/fail + saveResult
    // Most files have: passingCount++; ... await saveResult(...)
    // or failingCount++; ... await saveResult(...)

    // Add persist call right before each saveResult inside the resource loop
    const lines = code.split('\n');
    const newLines = [];
    for (let i = 0; i < lines.length; i++) {
      // Before saveResult, if prev lines had passingCount or failingCount, insert persist
      if (lines[i].includes('saveResult') && !lines[i].includes('import')) {
        // Look back to find if this is inside a resource loop
        const indent = lines[i].match(/^\s*/)[0];
        newLines.push(`${indent}await persistResourceFinding({ company, accountID: accountId || account?.get(t.id), entityType: ${entityType}, vertex: ${resourceVar}, controlId: ${controlId}, status: passingCount > failingCount ? 'PASS' : 'FAIL', resourceId: getValue(${resourceVar}, 'name') });`);
      }
      newLines.push(lines[i]);
    }
    code = newLines.join('\n');
    writeFileSync(file, code);
    modified++;
    continue;
  }

  // Pattern C: passing/failing in standalone function (macie, some ecs, pca)
  if (code.includes('passing++') || code.includes('failing++')) {
    const forOfMatch = code.match(/for \(const (\w+) of \w+\)\s*\{[\s\S]*?(passing|good)\+\+/);
    const resourceVar = forOfMatch ? forOfMatch[1] : 'resource';
    const controlId = controlIdMatch ? `'${controlIdMatch[1]}'` : "'unknown'";

    // Find pass/fail ternary or if blocks
    // Most have: result.status === 'PASS' ? passing++ : failing++ or good++/bad++
    if (code.includes("result.status === 'PASS' ? good++ : bad++")) {
      code = code.replace(
        "result.status === 'PASS' ? good++ : bad++;",
        `result.status === 'PASS' ? good++ : bad++;\n      await persistResourceFinding({ company, accountID, entityType: ${entityType}, vertex: ${resourceVar}, controlId: ${controlId}, status: result.status === 'PASS' ? 'PASS' : 'FAIL', resourceId: getValue(${resourceVar}, 'name') });`
      );
    }
    writeFileSync(file, code);
    modified++;
    continue;
  }

  // Fallback: couldn't determine pattern
  console.log(`SKIP (unknown pattern): ${file}`);
  skipped++;
}

console.log(`Modified: ${modified}, Skipped: ${skipped}, Total: ${files.length}`);
