          if (lines[j].trim()) break;
        }
        out.push(indent + "await persistResourceFinding({ company, accountID: accountId, entityType: " + entityType + ", vertex: " + rv + ", controlId: " + cid + ", status: " + status + ", resourceId: getValue(" + rv + ", 'name') });");
      }
