import { getValue, saveResult, persistResourceFinding } from "../../analyser/index.js";
import { AwsResourceType as EntityType, AwsResourceTypeLabel as EntityTypeLabel } from "../../../../shared/constants/aws-resource.constants.ts";

function getEntityValue(entity, key) {
    const value = entity.get(key);
    return value ? value[0] : null;
}

export async function runVPCPeeringControls(company, accounts, g, t, awsStandard) {
    // Cache peering connections per account
    const peeringByAccount = new Map();

    for (const account of accounts) {
        const accountID = account.get(t.id);
        const peerings = await g.V()
            .has('customer', company)
            .has('accountID', accountID)
            .has('entityType', EntityType.VPC_PEERING)
            .hasLabel(EntityTypeLabel.VPC_PEERING)
            .valueMap(true)
            .toList();

        peeringByAccount.set(accountID, peerings || []);
        console.log(`VPC Peering data for account ${accountID}: ${peerings.length} connections`);
    }

    // Collect all known account IDs from the org (accounts in this analysis run)
    const knownAccountIDs = new Set();
    for (const account of accounts) {
        knownAccountIDs.add(account.get(t.id));
    }

    await soteria_47291(company, accounts, peeringByAccount, knownAccountIDs, g, t, awsStandard);
    await soteria_83156(company, accounts, peeringByAccount, g, t, awsStandard);
}

/**
 * soteria_47291 — VPC peering connections should only be to accounts within the organisation.
 *
 * Checks that both the requester and accepter VPC owner IDs are in the set
 * of known accounts for this company. Peering to an unknown external account
 * is flagged as FAIL.
 */
async function soteria_47291(company, accounts, peeringByAccount, knownAccountIDs, g, t, awsStandard) {
    for (const account of accounts) {
        const accountID = account.get(t.id);
        const peerings = peeringByAccount.get(accountID) || [];

        if (peerings.length === 0) {
            await saveResult(company, awsStandard, 'V1.0', 'soteria_47291', '1', accountID, 0, 0);
            continue;
        }

        let passing = 0;
        let failing = 0;

        for (const peering of peerings) {
            let peerAccountIsKnown = true;

            try {
                const requesterRaw = getEntityValue(peering, 'requesterVpcInfo');
                const accepterRaw = getEntityValue(peering, 'accepterVpcInfo');
                const requester = requesterRaw ? JSON.parse(requesterRaw) : {};
                const accepter = accepterRaw ? JSON.parse(accepterRaw) : {};

                const requesterOwner = requester.OwnerId;
                const accepterOwner = accepter.OwnerId;

                if (requesterOwner && !knownAccountIDs.has(requesterOwner)) {
                    peerAccountIsKnown = false;
                }
                if (accepterOwner && !knownAccountIDs.has(accepterOwner)) {
                    peerAccountIsKnown = false;
                }
            } catch (e) {
                console.error('Error parsing VPC peering info:', e);
                peerAccountIsKnown = false;
            }

            if (peerAccountIsKnown) {
                passing++;
            } else {
                failing++;
            }

            await persistResourceFinding({
                company, accountID, entityType: EntityType.VPC_PEERING, vertex: peering,
                controlId: 'soteria_47291',
                status: peerAccountIsKnown ? 'PASS' : 'FAIL',
                resourceId: getEntityValue(peering, 'vpcPeeringConnectionId'),
                controlTitle: 'VPC peering connections should only be to accounts within the organisation',
            });
        }

        const testResult = failing === 0 ? '1' : '0';
        await saveResult(company, awsStandard, 'V1.0', 'soteria_47291', testResult, accountID, passing, failing);
    }
}

/**
 * soteria_83156 — VPC peering connections should be in active state.
 *
 * A pending, expired, rejected, or failed peering connection may indicate
 * a misconfiguration or abandoned infrastructure that should be cleaned up.
 */
async function soteria_83156(company, accounts, peeringByAccount, g, t, awsStandard) {
    for (const account of accounts) {
        const accountID = account.get(t.id);
        const peerings = peeringByAccount.get(accountID) || [];

        if (peerings.length === 0) {
            await saveResult(company, awsStandard, 'V1.0', 'soteria_83156', '1', accountID, 0, 0);
            continue;
        }

        let passing = 0;
        let failing = 0;

        for (const peering of peerings) {
            let isActive = false;

            try {
                const statusRaw = getEntityValue(peering, 'status');
                const status = statusRaw ? JSON.parse(statusRaw) : {};
                isActive = status.Code === 'active';
            } catch (e) {
                console.error('Error parsing VPC peering status:', e);
            }

            if (isActive) {
                passing++;
            } else {
                failing++;
            }

            await persistResourceFinding({
                company, accountID, entityType: EntityType.VPC_PEERING, vertex: peering,
                controlId: 'soteria_83156',
                status: isActive ? 'PASS' : 'FAIL',
                resourceId: getEntityValue(peering, 'vpcPeeringConnectionId'),
                controlTitle: 'VPC peering connections should be in active state',
            });
        }

        const testResult = failing === 0 ? '1' : '0';
        await saveResult(company, awsStandard, 'V1.0', 'soteria_83156', testResult, accountID, passing, failing);
    }
}

import { getValue, saveResult, persistResourceFinding } from "../../analyser/index.js";
import { AwsResourceType as EntityType, AwsResourceTypeLabel as EntityTypeLabel } from "../../../../shared/constants/aws-resource.constants.ts";

function getEntityValue(entity, key) {
    const value = entity.get(key);
    return value ? value[0] : null;
}

export async function runEBSSnapshotControls(company, accounts, g, t, awsStandard) {
    const snapshotsByAccount = new Map();

    for (const account of accounts) {
        const accountID = account.get(t.id);
        const snapshots = await g.V()
            .has('customer', company)
            .has('accountID', accountID)
            .has('entityType', EntityType.EBS_SNAPSHOT)
            .hasLabel(EntityTypeLabel.EBS_SNAPSHOT)
            .valueMap(true)
            .toList();

        snapshotsByAccount.set(accountID, snapshots || []);
        console.log(`EBS Snapshot data for account ${accountID}: ${snapshots.length} snapshots`);
    }

    await soteria_72418(company, accounts, snapshotsByAccount, g, t, awsStandard);
    await soteria_59834(company, accounts, snapshotsByAccount, g, t, awsStandard);
}

/**
 * soteria_72418 — EBS snapshots should be encrypted.
 *
 * Unencrypted snapshots expose data at rest. Aligns with EC2.3 from AWS FSBP.
 */
async function soteria_72418(company, accounts, snapshotsByAccount, g, t, awsStandard) {
    for (const account of accounts) {
        const accountID = account.get(t.id);
        const snapshots = snapshotsByAccount.get(accountID) || [];

        if (snapshots.length === 0) {
            await saveResult(company, awsStandard, 'V1.0', 'soteria_72418', '1', accountID, 0, 0);
            continue;
        }

        const failedSnapshots = snapshots.filter(snapshot => {
            const encrypted = getEntityValue(snapshot, 'encrypted');
            return encrypted !== true && encrypted !== 'true';
        });

        const passing = snapshots.length - failedSnapshots.length;
        const failing = failedSnapshots.length;

        for (const snapshot of snapshots) {
            const isFailing = failedSnapshots.includes(snapshot);
            await persistResourceFinding({
                company, accountID, entityType: EntityType.EBS_SNAPSHOT, vertex: snapshot,
                controlId: 'soteria_72418',
                status: isFailing ? 'FAIL' : 'PASS',
                resourceId: getEntityValue(snapshot, 'name') || getEntityValue(snapshot, 'aws_arn'),
                controlTitle: 'EBS snapshots should be encrypted',
            });
        }

        const testResult = failing === 0 ? '1' : '0';
        await saveResult(company, awsStandard, 'V1.0', 'soteria_72418', testResult, accountID, passing, failing);
    }
}

/**
 * soteria_59834 — EBS snapshots should not be publicly restorable.
 *
 * A snapshot with restorableByUserIds containing 'all' is publicly shared.
 * Aligns with EC2.1 from AWS FSBP.
 */
async function soteria_59834(company, accounts, snapshotsByAccount, g, t, awsStandard) {
    for (const account of accounts) {
        const accountID = account.get(t.id);
        const snapshots = snapshotsByAccount.get(accountID) || [];

        if (snapshots.length === 0) {
            await saveResult(company, awsStandard, 'V1.0', 'soteria_59834', '1', accountID, 0, 0);
            continue;
        }

        const failedSnapshots = snapshots.filter(snapshot => {
            const restorableByUserIds = getEntityValue(snapshot, 'restorableByUserIds');
            if (Array.isArray(restorableByUserIds) && restorableByUserIds.includes('all')) {
                return true;
            }
            return false;
        });

        const passing = snapshots.length - failedSnapshots.length;
        const failing = failedSnapshots.length;

        for (const snapshot of snapshots) {
            const isFailing = failedSnapshots.includes(snapshot);
            await persistResourceFinding({
                company, accountID, entityType: EntityType.EBS_SNAPSHOT, vertex: snapshot,
                controlId: 'soteria_59834',
                status: isFailing ? 'FAIL' : 'PASS',
                resourceId: getEntityValue(snapshot, 'name') || getEntityValue(snapshot, 'aws_arn'),
                controlTitle: 'EBS snapshots should not be publicly restorable',
            });
        }

        const testResult = failing === 0 ? '1' : '0';
        await saveResult(company, awsStandard, 'V1.0', 'soteria_59834', testResult, accountID, passing, failing);
    }
}

