export async function processAnalysisEvent(event: AnalysisEvent): Promise<ProcessAnalysisResult> {
    console.log('received event ' + JSON.stringify(event));

    const company = event.companyID;
    const currentRunID = `${company}-CIS_AWS-${new Date().toISOString()}`;
    await saveRun(company, awsStandard, 'V1.0', currentRunID);
    let accounts = await getAccounts(company);

    // Filter to a single account when accountID is provided (Batch mode)
    if (event.accountID) {
        accounts = accounts.filter((item) => item.get(t.id) === event.accountID);
        console.log(`Filtered to account ${event.accountID}, found ${accounts.length} match(es)`);
        if (accounts.length === 0) {
            console.error(`Account ${event.accountID} not found or not active for company ${company}`);
            return { statusCode: 404, body: JSON.stringify({ error: true, message: 'Account not found' }) };
        }
    }

