//import { setupConsoleOverride } from "@shared/utils/console-override";
//setupConsoleOverride();

import { processAnalysisEvent } from "@shared/services/analyser";
import { AnalysisEvent } from "@shared/models/analyser.types";
import { validate } from "@shared/utils/validator";
import z from 'zod';
import { withErrorHandling } from "@shared/middleware/error-handler";

export const analysisEventSchema = z.object({
    companyID: z.string(),
    accountID: z.string().optional(),
});

const handlerLogic = async (event: any): Promise<void> => {
  console.log("Starting CloudRisk analysis job!!");
  const validatedEvent: AnalysisEvent = validate(analysisEventSchema, event);
  console.log("Event validated successfully");
  await processAnalysisEvent(validatedEvent);
  console.log("Analysis job completed successfully");
};

// Lambda handler — invoked by AWS Lambda
export const handler = async (event: any): Promise<void> => {
  return await withErrorHandling(() => handlerLogic(event))();
};

// Batch entry point — reads EVENT from env var, same as the scanner
const isBatch = !!process.env.EVENT;
if (isBatch) {
  const run = async (): Promise<void> => {
    const eventJson: string = process.env.EVENT || "{}";
    console.log("Batch mode — EVENT:", eventJson);
    const rawEvent = JSON.parse(eventJson);
    const validatedEvent: AnalysisEvent = validate(analysisEventSchema, rawEvent);
    console.log("Event validated successfully");
    await processAnalysisEvent(validatedEvent);
    console.log("Analysis batch job completed successfully");
    process.exit(0);
  };
  withErrorHandling(run)();
}

