// --- trigger_analysis ---
server.tool(
    'trigger_analysis',
    'Trigger a compliance analysis run for an organisation. This evaluates scanned resources against compliance controls (e.g. CIS benchmarks) and writes results to DynamoDB. The analysis runs asynchronously — use get_jobs to monitor progress.',
    {
        companyID: z.string().describe('The company/client ID (e.g. "acta", "cko") — this is the "client" field from list_organisations'),
    },
    async ({ companyID }) => {
        try {
            const params = {
                FunctionName: 'crAnalysis',
                InvocationType: 'Event',
                Payload: new TextEncoder().encode(JSON.stringify({ companyID })),
            };

            const response = await lambda.send(new InvokeCommand(params));

            return {
                content: [{
                    type: 'text',
                    text: JSON.stringify({
                        success: true,
                        message: `Analysis triggered for ${companyID}`,
                        statusCode: response.StatusCode,
                    }, null, 2)
                }]
            };
        } catch (error) {
            return { content: [{ type: 'text', text: JSON.stringify({ error: error.message }) }] };
        }
    }
);

