// --- trigger_analysis ---
server.tool(
    'trigger_analysis',
    'Trigger compliance analysis as AWS Batch jobs. Submits one Batch job per accountID. Each job evaluates scanned resources against compliance controls and writes results to DynamoDB + Neptune. Use get_batch_jobs to monitor progress.',
    {
        companyID: z.string().describe('The company/client ID (e.g. "acta", "cko") — this is the "client" field from list_organisations'),
        accountIDs: z.array(z.string()).describe('AWS account IDs to analyse. Each gets its own Batch job.'),
    },
    async ({ companyID, accountIDs }) => {
        try {
            const submitted = [];
            for (const accountID of accountIDs) {
                const event = JSON.stringify({ companyID, accountID });
                const result = await batch.send(new SubmitJobCommand({
                    jobName: `crAnalysis-${companyID}-${accountID}`,
                    jobQueue: 'crBatch',
                    jobDefinition: 'crScanner',
                    containerOverrides: {
                        environment: [
                            { name: 'EVENT', value: event },
                            { name: 'ENTRY', value: 'analyser' },
                        ],
                    },
                }));
                submitted.push({ accountID, jobId: result.jobId });
            }

            return {
                content: [{
                    type: 'text',
                    text: JSON.stringify({
                        success: true,
                        message: `Analysis triggered for ${companyID}: ${submitted.length} Batch job(s) submitted`,
                        jobs: submitted,
                    }, null, 2)
                }]
            };
        } catch (error) {
            return { content: [{ type: 'text', text: JSON.stringify({ error: error.message }) }] };
        }
    }
);
